#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
CI n_=100009;
int n,q,m,a[n_],o,x,y,k;
int ad[n_*4],mu[n_*4],s[n_*4];
struct nd{int l,r;}t[n_*4];
void pu(int p)
{
	s[p]=(s[p*2]+s[p*2+1])%m;
}
void bd(int p,int l,int r)
{
	t[p].l=l;
	t[p].r=r;
	ad[p]=0;
	mu[p]=1;
	if(l==r)
	{
		s[p]=a[l]%m;
		return;
	}
	int mi=(l+r)/2;
	bd(p*2,l,mi);
	bd(p*2+1,mi+1,r);
	pu(p);
}
void pd(int p)
{
	int mi=(t[p].l+t[p].r)/2;
	s[p*2]=(s[p*2]*mu[p]%m+(mi-t[p].l+1)*ad[p]%m)%m;
	mu[p*2]=mu[p*2]*mu[p]%m;//pushdown
	ad[p*2]=(ad[p*2]*mu[p]%m+ad[p])%m;
	s[p*2+1]=(s[p*2+1]*mu[p]%m+(t[p].r-mi)*ad[p]%m)%m;
	mu[p*2+1]=mu[p*2+1]*mu[p]%m;
	ad[p*2+1]=(ad[p*2+1]*mu[p]%m+ad[p])%m;
	ad[p]=0;
	mu[p]=1;
}
void ua(int p,int l,int r,int x,int y,int k)
{
	if(x<=l&&y>=r)
	{
		s[p]=(s[p]+(r-l+1)*k%m)%m;
		ad[p]=(ad[p]+k)%m;
		return;
	}
	pd(p);
	int mi=(l+r)/2;
	if(x<=mi)
	{
		ua(p*2,l,mi,x,y,k);
	}
	if(y>mi)
	{
		ua(p*2+1,mi+1,r,x,y,k);
	}
	pu(p);
}
void um(int p,int l,int r,int x,int y,int k)
{
	if(x<=l&&y>=r)
	{
		s[p]=s[p]*k%m;
		ad[p]=ad[p]*k%m;
		mu[p]=mu[p]*k%m;
		return;
	}
	pd(p);
	int mi=(l+r)/2;
	if(x<=mi)
	{
		um(p*2,l,mi,x,y,k);
	}
	if(y>mi)
	{
		um(p*2+1,mi+1,r,x,y,k);
	}
	pu(p);
}
int qr(int p,int l,int r,int x,int y)
{
	if(l>=x&&r<=y)
	{
		return s[p]%m;
	}
	pd(p);
	int mi=(l+r)/2;
	int an=0;
	if(x<=mi)
	{
		an=(an+qr(p*2,l,mi,x,y))%m;
	}
	if(y>mi)
	{
		an=(an+qr(p*2+1,mi+1,r,x,y))%m;
	}
	return an%m;
}
int qp(int a,int b)
{
	int an=1;
	wh(b)
	{
		if(b&1)
		{
			an=an*a;
		}
		a=a*a;
		b>>=1;
	}
	return an;
}
signed main(void)
{
	IOS
	cin>>n>>q>>m;
	FOR(i,1,n)
	{
		cin>>a[i];
	}
	bd(1,1,n);
	wh(q--)
	{
		cin>>o>>x>>y;
		if(o==1)
		{
			cin>>k;
			um(1,1,n,x,y,k);
		}
		else if(o==2)
		{
			cin>>k;
			ua(1,1,n,x,y,k);
		}
		else
		{
			cout<<qr(1,1,n,x,y)%m<<'\n';
		}
	}
	return 0;
}
